// ============================================================
// Server-side session/challenge tracking for level attempts
// ============================================================
const activeLevelSessions = new Map(); // sessionToken -> { userId, levelId, startedAt, challengeNonce }

// ============================================================
// Utility functions
// ============================================================
function generateId() {
  return crypto.randomUUID();
}

function generateNonce() {
  return crypto.randomBytes(32).toString('hex');
}

function hashPassword(password, salt) {
  return crypto.pbkdf2Sync(password, salt, 100000, 64, 'sha512').toString('hex');
}

function computeHMAC(data, secret) {
  return crypto.createHmac('sha256', secret).update(JSON.stringify(data)).digest('hex');
}

// Server-side secret for HMAC verification of challenge responses
const SERVER_SECRET = process.env.SERVER_SECRET || crypto.randomBytes(64).toString('hex');

// ============================================================
// Authentication middleware
// ============================================================
function authenticate(req, res, next) {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Authentication required.' });
  }
  const token = authHeader.slice(7);
  const session = sessions.get(token);
  if (!session) {
    return res.status(401).json({ error: 'Invalid or expired session.' });
  }
  if (Date.now() > session.expiresAt) {
    sessions.delete(token);
    return res.status(401).json({ error: 'Session expired.' });
  }
  req.userId = session.userId;
  req.sessionToken = token;
  next();
}

// ============================================================
// Anomaly detection: statistical analysis of player behavior
// ============================================================
function detectAnomalies(userId, levelId, score, timeSeconds) {
  const config = LEVEL_CONFIG[levelId];
  const flags = [];

  // 1. Impossible score
  if (score > config.maxScore) {
    flags.push(`score_exceeds_max: ${score} > ${config.maxScore}`);
  }
  if (score < 0) {
    flags.push(`negative_score: ${score}`);
  }
  if (!Number.isInteger(score)) {
    flags.push(`non_integer_score: ${score}`);
  }

  // 2. Impossible time
  if (timeSeconds < config.minTime) {
    flags.push(`time_below_minimum: ${timeSeconds}s < ${config.minTime}s`);
  }
  if (timeSeconds > config.maxTime) {
    flags.push(`time_exceeds_maximum: ${timeSeconds}s > ${config.maxTime}s`);
  }

  // 3. Check completion frequency (rapid successive completions)
  const userCompletions = levelCompletions.get(userId) || [];
  const recentCompletions = userCompletions.filter(
    c => c.levelId === levelId && (Date.now() - c.completedAt) < 5 * 60 * 1000
  );
  if (recentCompletions.length >= 3) {
    flags.push(`rapid_repeat_completion: ${recentCompletions.length} times in 5 min for level ${levelId}`);
  }

  // 4. Statistical outlier detection against player's own history
  const levelHistory = userCompletions.filter(c => c.levelId === levelId);
  if (levelHistory.length >= 5) {
    const avgScore = levelHistory.reduce((sum, c) => sum + c.score, 0) / levelHistory.length;
    const stdDev = Math.sqrt(
      levelHistory.reduce((sum, c) => sum + Math.pow(c.score - avgScore, 2), 0) / levelHistory.length
    );
    if (stdDev > 0 && Math.abs(score - avgScore) > 3 * stdDev) {
      flags.push(`statistical_outlier_score: ${score} vs avg ${avgScore.toFixed(1)} (stddev ${stdDev.toFixed(1)})`);
    }

    const avgTime = levelHistory.reduce((sum, c) => sum + c.timeSeconds, 0) / levelHistory.length;
    const timeStdDev = Math.sqrt(
      levelHistory.reduce((sum, c) => sum + Math.pow(c.timeSeconds - avgTime, 2), 0) / levelHistory.length
    );
    if (timeStdDev > 0 && (avgTime - timeSeconds) > 3 * timeStdDev) {
      flags.push(`statistical_outlier_time: ${timeSeconds}s vs avg ${avgTime.toFixed(1)}s`);
    }
  }

  // 5. Score-to-time ratio check (high score in very little time is suspicious)
  const scorePerSecond = score / Math.max(timeSeconds, 1);
  const maxReasonableRate = config.maxScore / config.minTime;
  if (scorePerSecond > maxReasonableRate * 0.9) {
    flags.push(`suspicious_score_rate: ${scorePerSecond.toFixed(2)} pts/s`);
  }

  return flags;
}

// ============================================================
// Server-authoritative reward calculation
// ============================================================
function calculateReward(levelId, score, timeSeconds) {
  const config = LEVEL_CONFIG[levelId];
  if (!config) return 0;

  // Clamp score to valid range
  const clampedScore = Math.max(0, Math.min(score, config.maxScore));
  const scoreRatio = clampedScore / config.maxScore;

  // Time bonus: faster (but still plausible) completion gets a bonus
  const timeRange = config.maxTime - config.minTime;
  const clampedTime = Math.max(config.minTime, Math.min(timeSeconds, config.maxTime));
  const timeRatio = 1 - ((clampedTime - config.minTime) / timeRange);

  // Weighted reward: 70% score, 30% time bonus
  const rewardMultiplier = (scoreRatio * 0.7) + (timeRatio * 0.3);
  const reward = Math.floor(config.baseReward + (config.maxReward - config.baseReward) * rewardMultiplier);

  // Clamp to configured bounds
  return Math.max(config.baseReward, Math.min(reward, config.maxReward));
}

