app.post('/api/levels/:levelId/start', authenticate, (req, res) => {
  const levelId = parseInt(req.params.levelId, 10);
  const user = users.get(req.userId);

  if (!user) {
    return res.status(404).json({ error: 'User not found.' });
  }
  if (user.isBanned) {
    return res.status(403).json({ error: 'Account suspended.' });
  }
  if (!LEVEL_CONFIG[levelId]) {
    return res.status(400).json({ error: 'Invalid level.' });
  }
  if (levelId > user.highestLevelUnlocked) {
    return res.status(403).json({ error: 'Level not yet unlocked.' });
  }

  // Invalidate any existing active session for this user+level
  for (const [key, session] of activeLevelSessions) {
    if (session.userId === req.userId && session.levelId === levelId) {
      activeLevelSessions.delete(key);
    }
  }

  // Create a server-tracked level session with a challenge nonce
  const levelSessionToken = generateId();
  const challengeNonce = generateNonce();

  activeLevelSessions.set(levelSessionToken, {
    userId: req.userId,
    levelId,
    startedAt: Date.now(),
    challengeNonce,
    used: false,
  });

  // Auto-expire after maxTime + buffer
  const config = LEVEL_CONFIG[levelId];
  setTimeout(() => {
    const session = activeLevelSessions.get(levelSessionToken);
    if (session && !session.used) {
      activeLevelSessions.delete(levelSessionToken);
    }
  }, (config.maxTime + 60) * 1000);

  res.json({
    levelSessionToken,
    challengeNonce,
    levelId,
    message: 'Level started. Submit completion with this session token.',
  });
});

