app.post('/api/levels/:levelId/complete', authenticate, levelCompletionLimiter, (req, res) => {
  const levelId = parseInt(req.params.levelId, 10);
  const { score, timeSeconds, levelSessionToken, challengeResponse, moveSequence } = req.body;
  const user = users.get(req.userId);

  if (!user) {
    return res.status(404).json({ error: 'User not found.' });
  }
  if (user.isBanned) {
    return res.status(403).json({ error: 'Account suspended.' });
  }

  // ---- Input validation ----
  if (!LEVEL_CONFIG[levelId]) {
    return res.status(400).json({ error: 'Invalid level.' });
  }
  if (typeof score !== 'number' || typeof timeSeconds !== 'number') {
    return res.status(400).json({ error: 'Score and timeSeconds must be numbers.' });
  }
  if (!Number.isFinite(score) || !Number.isFinite(timeSeconds)) {
    return res.status(400).json({ error: 'Score and timeSeconds must be finite numbers.' });
  }
  if (!levelSessionToken || typeof levelSessionToken !== 'string') {
    return res.status(400).json({ error: 'levelSessionToken is required.' });
  }
  if (!challengeResponse || typeof challengeResponse !== 'string') {
    return res.status(400).json({ error: 'challengeResponse is required.' });
  }

  // ---- Validate level session ----
  const levelSession = activeLevelSessions.get(levelSessionToken);
  if (!levelSession) {
    return res.status(400).json({ error: 'Invalid or expired level session.' });
  }
  if (levelSession.used) {
    return res.status(400).json({ error: 'Level session already used.' });
  }
  if (levelSession.userId !== req.userId) {
    return res.status(403).json({ error: 'Level session does not belong to this user.' });
  }
  if (levelSession.levelId !== levelId) {
    return res.status(400).json({ error: 'Level session does not match requested level.' });
  }

  // ---- Verify challenge-response (anti-replay, anti-bot) ----
  // The client must compute HMAC(nonce + score + timeSeconds + levelId, clientSecret)
  // For our server verification, we check the server-side HMAC
  const expectedResponse = computeHMAC(
    { nonce: levelSession.challengeNonce, score, timeSeconds, levelId },
    SERVER_SECRET
  );
  // In production, the client would have a shared secret or use a more sophisticated
  // challenge-response. Here we verify the server can reconstruct the expected value.
  // The client SDK would need to compute this using an obfuscated key.
  if (challengeResponse !== expectedResponse) {
    user.flagCount += 2;
    return res.status(400).json({ error: 'Invalid challenge response. Potential tampering detected.' });
  }

  // ---- Verify server-side elapsed time ----
  const serverElapsedMs = Date.now() - levelSession.startedAt;
  const serverElapsedSeconds = serverElapsedMs / 1000;
  const config = LEVEL_CONFIG[levelId];

  // Client-reported time should be reasonably close to server-measured time
  const timeDifference = Math.abs(serverElapsedSeconds - timeSeconds);
  const timeToleranceSeconds = 5; // Allow 5 seconds of network/processing variance
  if (timeDifference > timeToleranceSeconds) {
    user.flagCount += 3;
    console.warn(`[ANOMALY] User ${req.userId}: time mismatch. Server: ${serverElapsedSeconds.toFixed(1)}s, Client: ${timeSeconds}s`);

    if (user.flagCount >= 10) {
      user.isBanned = true;
      return res.status(403).json({ error: 'Account suspended for suspicious activity.' });
    }
    return res.status(400).json({ error: 'Time verification failed.' });
  }

  // Use server-measured time as the authoritative time
  const authoritativeTime = Math.round(serverElapsedSeconds);

  // ---- Validate move sequence (basic plausibility) ----
  if (moveSequence) {
    if (!Array.isArray(moveSequence)) {
      return res.status(400).json({ error: 'moveSequence must be an array.' });
    }
    // Check that move count is plausible for the score
    const minMovesForScore = Math.floor(score / 100); // rough heuristic
    if (moveSequence.length < minMovesForScore) {
      user.flagCount += 1;
      console.warn(`[ANOMALY] User ${req.userId}: too few moves (${moveSequence.length}) for score ${score}`);
    }
  }

  // ---- Anomaly detection ----
  const anomalyFlags = detectAnomalies(req.userId, levelId, score, authoritativeTime);
  if (anomalyFlags.length > 0) {
    user.flagCount += anomalyFlags.length;
    console.warn(`[ANOMALY] User ${req.userId}, Level ${levelId}: ${anomalyFlags.join('; ')}`);

    if (user.flagCount >= 10) {
      user.isBanned = true;
      activeLevelSessions.delete(levelSessionToken);
      return res.status(403).json({ error: 'Account suspended for suspicious activity.' });
    }

    // If there are critical flags, reject the completion
    const criticalFlags = anomalyFlags.filter(f =>
      f.startsWith('score_exceeds_max') ||
      f.startsWith('negative_score') ||
      f.startsWith('time_below_minimum')
    );
    if (criticalFlags.length > 0) {
      activeLevelSessions.delete(levelSessionToken);
      return res.status(400).json({ error: 'Level completion rejected due to invalid data.' });
    }
  }

  // ---- Mark session as used (prevent replay) ----
  levelSession.used = true;
  activeLevelSessions.delete(levelSessionToken);

  // ---- Server-authoritative reward calculation ----
  // We do NOT trust client-reported reward amounts
  const clampedScore = Math.max(0, Math.min(Math.floor(score), config.maxScore));
  const reward = calculateReward(levelId, clampedScore, authoritativeTime);

  // ---- Record completion ----
  const completionId = generateId();
  const completionRecord = {
    completionId,
    userId: req.userId,
    levelId,
    score: clampedScore,
    timeSeconds: authoritativeTime,
    clientReportedTime: timeSeconds,
    reward,
    anomalyFlags,
    completedAt: Date.now(),
  };

  if (!levelCompletions.has(req.userId)) {
    levelCompletions.set(req.userId, []);
  }
  levelCompletions.get(req.userId).push(completionRecord);

  // ---- Create pending reward (must be explicitly claimed) ----
  const rewardId = generateId();
  pendingRewards.set(rewardId, {
    rewardId,
    userId: req.userId,
    completionId,
    levelId,
    amount: reward,
    createdAt: Date.now(),
    expiresAt: Date.now() + 24 * 60 * 60 * 1000, // 24 hour expiry
  });

  // ---- Unlock next level ----
  if (levelId >= user.highestLevelUnlocked && levelId < Object.keys(LEVEL_CONFIG).length) {
    user.highestLevelUnlocked = levelId + 1;
  }

  res.json({
    completionId,
    rewardId,
    score: clampedScore,
    timeSeconds: authoritativeTime,
    reward,
    message: 'Level completed! Claim your reward.',
    anomalyWarning: anomalyFlags.length > 0 ? 'Some metrics were flagged for review.' : undefined,
  });
});

