app.post('/api/rewards/:rewardId/claim', authenticate, rewardClaimLimiter, (req, res) => {
  const { rewardId } = req.params;
  const user = users.get(req.userId);

  if (!user) {
    return res.status(404).json({ error: 'User not found.' });
  }
  if (user.isBanned) {
    return res.status(403).json({ error: 'Account suspended.' });
  }

  // ---- Validate reward exists ----
  const reward = pendingRewards.get(rewardId);
  if (!reward) {
    return res.status(404).json({ error: 'Reward not found or already claimed.' });
  }

  // ---- Verify ownership ----
  if (reward.userId !== req.userId) {
    return res.status(403).json({ error: 'This reward does not belong to you.' });
  }

  // ---- Check expiry ----
  if (Date.now() > reward.expiresAt) {
    pendingRewards.delete(rewardId);
    return res.status(410).json({ error: 'Reward has expired.' });
  }

  // ---- Prevent double-claim ----
  if (claimedRewards.has(rewardId)) {
    return res.status(409).json({ error: 'Reward already claimed.' });
  }

  // ---- Award coins (server-authoritative amount) ----
  // We use the server-calculated reward amount, NOT anything from the client
  user.coins += reward.amount;
  claimedRewards.add(rewardId);
  pendingRewards.delete(rewardId);

  res.json({
    rewardId,
    amountClaimed: reward.amount,
    totalCoins: user.coins,
    message: 'Reward claimed successfully!',
  });
});

