app.get('/api/rewards/pending', authenticate, (req, res) => {
  const userRewards = [];
  for (const [, reward] of pendingRewards) {
    if (reward.userId === req.userId && Date.now() <= reward.expiresAt) {
      userRewards.push({
        rewardId: reward.rewardId,
        levelId: reward.levelId,
        amount: reward.amount,
        expiresAt: reward.expiresAt,
      });
    }
  }
  res.json({ rewards: userRewards });
});

