app.get('/api/profile', authenticate, (req, res) => {
  const user = users.get(req.userId);
  if (!user) {
    return res.status(404).json({ error: 'User not found.' });
  }

  const completions = levelCompletions.get(req.userId) || [];
  const levelStats = {};
  for (const c of completions) {
    if (!levelStats[c.levelId]) {
      levelStats[c.levelId] = { bestScore: 0, bestTime: Infinity, completionCount: 0 };
    }
    const ls = levelStats[c.levelId];
    ls.bestScore = Math.max(ls.bestScore, c.score);
    ls.bestTime = Math.min(ls.bestTime, c.timeSeconds);
    ls.completionCount++;
  }

  res.json({
    userId: user.userId,
    username: user.username,
    coins: user.coins,
    highestLevelUnlocked: user.highestLevelUnlocked,
    levelStats,
    totalCompletions: completions.length,
  });
});

